+    RCLCPP_ERROR(get_logger("client"), "unexpectedly failed: %s", e.what());
+  }catch(const SetErrorException & e) {
+    RCLCPP_ERROR(get_logger("client"), "unexpectedly failed: %s", e.what());
+  }
+
+  rclcpp::shutdown();
+
+  return 0;
+}

