+        }
+        case rclcpp::ParameterType::PARAMETER_BOOL:
+        {
+          bool value = param.as_bool();
+          RCLCPP_INFO(this->get_logger(), "GET OPERATION : parameter %s's value is %s", param_name.c_str(), value?"true":"false");
